mapper.select:
select d.*, p.name as parent_name from departments d left join departments p on p.id = d.parent_id
and d.name like concat('%', #{name}, '%')
and d.is_active = #{isActive}
and d.parent_id = #{parentId}
order by d.id asc

select count(1)
from departments
where name = #{name}
  and id <> #{excludeId}

select count(1)
from users
where department_id = #{id}

select count(1)
from cases
where department_id = #{id}

select count(1)
from departments
where parent_id = #{id}
